                                            )}
                                            {getAuditStatusBadge(audit.status)}
                                            <ChevronRight className="w-5 h-5 text-ch-text-dimmed group-hover:text-ch-orange group-hover:translate-x-1 transition-all" />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </motion.div>
                    )}
                </div>
            </div>

            {/* Preview Dialog */}
            <AnimatePresence>
                {isPreviewOpen && (
                    <Dialog open={isPreviewOpen} onOpenChange={setIsPreviewOpen}>
                        <DialogContent className="max-w-4xl h-[85vh] flex flex-col bg-ch-black-soft border-white/10 p-0 overflow-hidden rounded-[2.5rem] shadow-[0_0_100px_rgba(242,106,33,0.15)]">
